entities.syntax:
BOOL BluetoothFindDeviceClose(   HBLUETOOTH_DEVICE_FIND hFind);
参数 hFind
要关闭的查询的句柄。 在对 BluetoothFindFirstDevice 函数的上一次调用中获取。

BOOL BluetoothFindRadioClose(   HBLUETOOTH_RADIO_FIND hFind);
参数 hFind
要关闭的枚举句柄，通过上一次调用 BluetoothFindFirstRadio 函数获取。

typedef struct _BLUETOOTH_COD_PAIRS {   ULONG   ulCODMask;
LPCWSTR pcszDescription;} BLUETOOTH_COD_PAIRS;
成员 ulCODMask
要比较以确定设备类别的掩码。 ulCODMask 的主要和次要代码用于比较找到的设备类。如果提供了主要代码，则它必须与远程设备返回的主要代码匹配，以便GET_COD_MAJOR
(ulCODMask) 等于 GET_COD_MAJOR ([远程设备的设备类]) 。 pcszDescription
掩码的描述性字符串。

typedef struct _BLUETOOTH_DEVICE_INFO {
DWORD             dwSize;   BLUETOOTH_ADDRESS Address;
ULONG             ulClassofDevice;
BOOL              fConnected;   BOOL              fRemembered;
BOOL              fAuthenticated;
SYSTEMTIME        stLastSeen;   SYSTEMTIME        stLastUsed;
WCHAR             szName[BLUETOOTH_MAX_NAME_SIZE];} BLUETOOTH_DEVICE_INFO_STRUCT;
成员 dwSize

typedef struct _BLUETOOTH_DEVICE_SEARCH_PARAMS {   DWORD  dwSize;
BOOL   fReturnAuthenticated;   BOOL   fReturnRemembered;
BOOL   fReturnUnknown;   BOOL   fReturnConnected;   BOOL   fIssueInquiry;
UCHAR  cTimeoutMultiplier;   HANDLE hRadio;
} BLUETOOTH_DEVICE_SEARCH_PARAMS;
成员 dwSize
结构的大小（以字节为单位）。 fReturnAuthenticated
一个 值，该值指定搜索应返回经过身份验证的蓝牙设备。 fReturnRemembered
一个 值，该值指定搜索应返回记住的蓝牙设备。 fReturnUnknown
一个 值，该值指定搜索应返回未知的蓝牙设备。 fReturnConnected
一个 值，该值指定搜索应返回连接的蓝牙设备。
fIssueInquiry
一个 值，该值指定应发出新的查询。 cTimeoutMultiplier
一个 值，该值指示查询的超时，以 1.28 秒的增量表示。 例如，12.8 秒的查询的
cTimeoutMultiplier 值为 10。 此成员的最大值为 48。 使用大于 48 的值时，调用函数会
立即失败并返回 E_INVALIDARG。 hRadio
要对其执行查询的无线电的句柄。 设置为 NULL 可对所有本地蓝牙无线电执行查询。

typedef struct _BLUETOOTH_FIND_RADIO_PARAMS {   DWORD dwSize;
} BLUETOOTH_FIND_RADIO_PARAMS;
成员 dwSize
BLUETOOTH_FIND_RADIO_PARAMS 结构的大小（以字节为单位）。

typedef struct _BLUETOOTH_NUMERIC_COMPARISON_INFO {   ULONG NumericValue;
} BLUETOOTH_NUMERIC_COMPARISON_INFO, *PBLUETOOTH_NUMERIC_COMPARISON_INFO;
成员 NumericValue 数值。

typedef struct _BLUETOOTH_OOB_DATA_INFO {
UCHAR C[16];   UCHAR R[16];
} BLUETOOTH_OOB_DATA_INFO, *PBLUETOOTH_OOB_DATA_INFO;

typedef struct _BLUETOOTH_PASSKEY_INFO {   ULONG passkey;
} BLUETOOTH_PASSKEY_INFO, *PBLUETOOTH_PASSKEY_INFO;
成员 passkey
用于身份验证的密钥。

typedef struct _BLUETOOTH_PIN_INFO {
UCHAR pin[BTH_MAX_PIN_SIZE];   UCHAR pinLength;
} BLUETOOTH_PIN_INFO, *PBLUETOOTH_PIN_INFO; 成员
pin[BTH_MAX_PIN_SIZE] 用于身份验证的 PIN。 pinLength
引脚的长度。

typedef struct _BLUETOOTH_RADIO_INFO {
DWORD             dwSize;   BLUETOOTH_ADDRESS address;
WCHAR             szName[BLUETOOTH_MAX_NAME_SIZE];
ULONG             ulClassofDevice;   USHORT            lmpSubversion;   USHORT            manufacturer;
} BLUETOOTH_RADIO_INFO, *PBLUETOOTH_RADIO_INFO;
成员 dwSize
结构的大小（以字节为单位）。 address
本地蓝牙无线电的地址。
szName[BLUETOOTH_MAX_NAME_SIZE]
本地蓝牙无线电的名称。 ulClassofDevice
本地蓝牙无线电的设备类。 lmpSubversion
此成员包含特定于单个蓝牙设备制造商的数据。 manufacturer
蓝牙无线电的制造商，表示为 BTH_MFG_Xxx 值。 有关蓝牙分配号码文档和当前值列表
的详细信息，请参阅 www.bluetooth.com 要求

typedef struct _BTH_RADIO_IN_RANGE {   BTH_DEVICE_INFO deviceInfo;
ULONG           previousDeviceFlags;
} BTH_RADIO_IN_RANGE, *PBTH_RADIO_IN_RANGE;
成员 deviceInfo
与远程设备关联的当前属性集，采用 BTH_DEVICE_INFO 结构的形式。 previousDeviceFlags
deviceInfo 成员指向的 BTH_DEVICE_INFO 结构的 flags 成员以前的标志。 用于确定与远
程设备关联的属性已更改。

typedef struct _SDP_STRING_TYPE_DATA {
USHORT encoding;   USHORT mibeNum;
USHORT attributeId;
} SDP_STRING_TYPE_DATA, *PSDP_STRING_TYPE_DATA;
成员 encoding
指定如何根据 ISO 639：1988 (E/F) ：语言名称表示形式的代码对字符串进行编码。 mibeNum
IANA 数据库中的 MIBE 编号。 attributeId
记录中要在其中找到字符串的基属性的标识符。

typedef struct SdpAttributeRange {
USHORT minAttribute;   USHORT maxAttribute;} SdpAttributeRange;
成员 minAttribute
要搜索的最小属性值。 maxAttribute
要搜索的最大属性值。

typedef struct _SdpQueryUuid {   SdpQueryUuidUnion u;
USHORT            uuidType;} SdpQueryUuid;
成员 u
包含要搜索的 UUID 的联合。 uuidType
正在搜索的 UUID 的类型。 必须是SDP_SPECIFICTYPE枚举中的三个有效值之一：

typedef union SdpQueryUuidUnion {
GUID   uuid128;   ULONG  uuid32;   USHORT uuid16;
} SdpQueryUuidUnion;
成员 uuid128
128 位格式的 UUID。 uuid32
32 位格式的 UUID。 uuid16
16 位格式的 UUID。

typedef struct _SOCKADDR_BTH {
USHORT   addressFamily;   BTH_ADDR btAddr;
GUID     serviceClassId;   ULONG    port;
} SOCKADDR_BTH, *PSOCKADDR_BTH;
成员 addressFamily
套接字的地址系列。 此成员始终AF_BTH。 btAddr
目标蓝牙设备的地址。 与 绑定 函数一起使用时，必须是零或有效的本地无线电地址。如果为零，则调用 connect 或 accept 函数时，会分配有效的本地蓝牙设备地址。 与
connect 函数一起使用时，必须指定有效的远程无线电地址。 serviceClassId
套接字的服务类标识符。 与 绑定 函数一起使用时， 将忽略 serviceClassId 。 如果指定了端口，也将被忽略。 对于 connect 函数，指定要连接到的服务的唯一蓝牙服务类 ID。 如果对等设备有多个与服务类标识符对应的端口， 则 connect 函数会尝试连接到第一个有
效服务;此机制无需事先进行 SDP 查询即可使用。 port
与套接字关联的 RFCOMM 通道。 请参阅“备注”。

DWORD BluetoothUpdateDeviceRecord(   const BLUETOOTH_DEVICE_INFO *pbtdi);
参数 pbtdi
指向要更新 的BLUETOOTH_DEVICE_INFO 结构的指针。 有关详细信息，请参见“备注”部分。

typedef struct _BLUETOOTH_LOCAL_SERVICE_INFO {
BOOL              Enabled;   BLUETOOTH_ADDRESS btAddr;
WCHAR             szName[BLUETOOTH_MAX_SERVICE_NAME_SIZE];
WCHAR             szDeviceString[BLUETOOTH_DEVICE_NAME_SIZE];} BLUETOOTH_LOCAL_SERVICE_INFO_STRUCT;

DWORD BluetoothSdpGetContainerElementData(
[in]      LPBYTE                       pContainerStream,   [in]      ULONG                        cbContainerLength,   [in, out] HBLUETOOTH_CONTAINER_ELEMENT *pElement,
[out]     PSDP_ELEMENT_DATA            pData);

typedef struct _BTH_SET_SERVICE {   PULONG pSdpVersion;
HANDLE *pRecordHandle;
ULONG  fCodService;   ULONG  Reserved[5];
ULONG  ulRecordLength;   UCHAR  pRecord[1];
} BTH_SET_SERVICE, *PBTH_SET_SERVICE, BTHNS_SETBLOB, *PBTHNS_SETBLOB;
成员 pSdpVersion
SDP 的版本。 客户端将此成员设置为 BTH_SDP_VERSION。 pRecordHandle
SDP 记录的句柄。 对应于 SDP ServiceRecordHandle。 由添加记录操作返回，随后用于
删除记录。 fCodService
设备 (COD) 信息的类。 与此 SDP 记录关联的COD_SERVICE_* 类设备位的 32 位字段。 系统将这些位与其他服务记录和系统特征中的 COD 位组合在一起。 当在设备查询期间找到无线电时，将播发本地无线电的生成的设备类。 删除与特定服务位关联的最后一条 SDP 记录时，不再在响应将来的设备查询时报告该服务位。
COD 字段的格式和可能值在 蓝牙规范第 1.2 节的蓝牙分配号码 1.1 部分中定义。 (此资源在某些语言和国家/地区中可能不可用。) Windows 使用的 COD_SERVICE_* 位的相应宏和定义在 Bthdef.h 中定义。 有关设备 (COD) 类的详细信息，请参阅 BTH_DEVICE_INFO。
Reserved[5]
保留。 必须设置为零。
ulRecordLength
pRecord 的大小（以字节为单位）。 pRecord[1]
SDP 记录，由蓝牙规范定义。

typedef struct _BTH_HCI_EVENT_INFO {   BTH_ADDR bthAddress;
UCHAR    connectionType;   UCHAR    connected;
} BTH_HCI_EVENT_INFO, *PBTH_HCI_EVENT_INFO;
成员 bthAddress
远程设备的地址，采用 BTH_ADDR 结构的形式。 connectionType
连接类型。 有效值为 HCI_CONNECTION_TYPE_ACL 或 HCI_CONNECTION_TYPE_SCO。 connected
连接的状态。 如果不是零，则已建立连接。 如果为零，则表示连接已终止。

typedef struct _BTH_QUERY_DEVICE {   ULONG LAP;
UCHAR length;
} BTH_QUERY_DEVICE, *PBTH_QUERY_DEVICE, BTHNS_INQUIRYBLOB, *PBTHNS_INQUIRYBLOB;
